#!/bin/bash
# Intégrations DevOps courantes

# Kubernetes
kubectl_safe() {
    local ctx=$1; shift
    kubectl --context="$ctx" "$@"
}

# Attendre qu'un deployment soit prêt
wait_deployment() {
    local ns=$1 name=$2
    kubectl rollout status deployment/"$name" -n "$ns" --timeout=120s
}

# Ansible
run_playbook() {
    ansible-playbook "$1" \
        -i "$2" \
        --vault-password-file ~/.vault_pass \
        "${@:3}"
}

# Consul (service discovery)
consul_get() {
    curl -sf "http://localhost:8500/v1/kv/$1?raw"
}
consul_set() {
    curl -sf -X PUT "http://localhost:8500/v1/kv/$1" -d "$2"
}

# Prometheus pushgateway
push_metric() {
    local metric=$1 value=$2 job=${3:-script}
    cat << EOF | curl -sf --data-binary @- \
        "http://pushgateway:9091/metrics/job/$job"
# TYPE $metric gauge
$metric $value
EOF
}

# Vault (secrets)
get_secret() {
    vault kv get -field="$2" "$1"
}
```

